/**
 * @param {number[]} nums
 * @return {number}
 */
function solve(nums) {
    // Step 1: Find the set S of unique values in nums for O(1) lookup.
    const S = new Set(nums);

    let totalSum = 0;

    // Step 2: For each element x in nums, find the smallest divisor d that is present in S.
    for (const x of nums) {
        let min_d = x; // Initialize with x, as x always divides x and x is in S

        // Find all divisors of x in O(sqrt(x))
        const limit = Math.floor(Math.sqrt(x));

        for (let i = 1; i <= limit; i++) {
            if (x % i === 0) {
                // i is a divisor (d1)
                const d1 = i;
                // x/i is a divisor (d2)
                const d2 = x / i;

                // Check d1
                if (S.has(d1)) {
                    if (d1 < min_d) {
                        min_d = d1;
                    }
                }

                // Check d2, ensuring we don't double-check if x is a perfect square
                if (d1 !== d2) {
                    if (S.has(d2)) {
                        if (d2 < min_d) {
                            min_d = d2;
                        }
                    }
                }
            }
        }

        totalSum += min_d;
    }

    return totalSum;
}

