import java.util.HashSet;
import java.util.Set;
import java.lang.Math;

public class Solution {
    public static long solve(long[] nums) {
        // Step 1: Find the set S of unique values in nums.
        Set<Long> S = new HashSet<>();
        for (long x : nums) {
            S.add(x);
        }

        long totalSum = 0;

        // Step 2: For each element x in nums, find the smallest divisor d that is present in S.
        for (long x : nums) {
            long min_d = x; // Initialize with x

            // Find all divisors of x in O(sqrt(x))
            // We iterate i up to sqrt(x)
            long limit = (long) Math.sqrt(x);

            for (long i = 1; i <= limit; i++) {
                if (x % i == 0) {
                    // i is a divisor (d1)
                    long d1 = i;
                    // x/i is a divisor (d2)
                    long d2 = x / i;

                    // Check d1
                    if (S.contains(d1)) {
                        if (d1 < min_d) {
                            min_d = d1;
                        }
                    }

                    // Check d2, ensuring we don't double-check if x is a perfect square
                    if (d1 != d2) {
                        if (S.contains(d2)) {
                            if (d2 < min_d) {
                                min_d = d2;
                            }
                        }
                    }
                }
            }

            totalSum += min_d;
        }

        return totalSum;
    }
}

